# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

import time
import uuid
import random
from flask import Flask, request, g
from prometheus_client import (
    Counter,
    Histogram,
    Gauge,
    generate_latest,
    CONTENT_TYPE_LATEST,
    CollectorRegistry,
    REGISTRY,
)

app = Flask(__name__)

# ── Prometheus Metrics ──────────────────────────────────────────────────────

# Counter: total HTTP requests with labels for user_id, session_id, and full path
http_requests_total = Counter(
    "http_requests_total",
    "Total number of HTTP requests",
    ["method", "user_id", "session_id", "path", "status"],
)

# Histogram: request duration with the same label set
http_request_duration_seconds = Histogram(
    "http_request_duration_seconds",
    "HTTP request duration in seconds",
    ["method", "user_id", "session_id", "path"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0),
)

# Gauge: in-flight requests per user-path combination
http_requests_in_progress = Gauge(
    "http_requests_in_progress",
    "Number of HTTP requests currently being processed",
    ["user_id", "path"],
)

# Counter: unique user-path combinations ever seen (acts as a cardinality tracker)
unique_user_path_combinations = Counter(
    "unique_user_path_combinations_total",
    "Number of unique user-path combinations observed",
    ["user_id", "path"],
)

# Gauge: per-user request rate tracker (last request timestamp)
user_last_request_timestamp = Gauge(
    "user_last_request_timestamp_seconds",
    "Timestamp of the last request for a given user-path combination",
    ["user_id", "path"],
)

# Counter: bytes transferred per user-path
http_response_bytes_total = Counter(
    "http_response_bytes_total",
    "Total response bytes per user-path combination",
    ["user_id", "path"],
)

# ── Track seen combinations for dynamic metric creation ─────────────────────

_seen_user_path_combos: set[tuple[str, str]] = set()
_dynamic_counters: dict[tuple[str, str], Counter] = {}


def _get_or_create_dynamic_counter(user_id: str, path: str) -> Counter:
    """Create a dedicated counter for each unique user-path combination."""
    key = (user_id, path)
    if key not in _dynamic_counters:
        safe_user = user_id.replace("-", "_").replace(".", "_")
        safe_path = path.strip("/").replace("/", "_").replace("-", "_") or "root"
        metric_name = f"http_user_path_requests__{safe_user}__{safe_path}"
        # Prometheus metric names must match [a-zA-Z_:][a-zA-Z0-9_:]*
        metric_name = "".join(c if c.isalnum() or c == "_" else "_" for c in metric_name)
        try:
            counter = Counter(
                metric_name,
                f"Request count for user={user_id} path={path}",
                ["method", "status"],
            )
        except ValueError:
            # Metric already registered (e.g. duplicate safe names) – reuse
            counter = _dynamic_counters.get(key)
            if counter is None:
                # Fallback: just use the shared counter
                counter = http_requests_total
        _dynamic_counters[key] = counter
    return _dynamic_counters[key]


# ── Middleware: before / after request hooks ─────────────────────────────────

def _resolve_user_id() -> str:
    """Extract user_id from header, query param, or generate one."""
    return (
        request.headers.get("X-User-Id")
        or request.args.get("user_id")
        or "anonymous"
    )


def _resolve_session_id() -> str:
    """Extract session_id from header, cookie, or query param."""
    return (
        request.headers.get("X-Session-Id")
        or request.cookies.get("session_id")
        or request.args.get("session_id")
        or str(uuid.uuid4())
    )


@app.before_request
def before_request_metrics():
    g.start_time = time.time()
    g.user_id = _resolve_user_id()
    g.session_id = _resolve_session_id()
    g.full_path = request.full_path.rstrip("?")  # includes query string

    http_requests_in_progress.labels(
        user_id=g.user_id, path=g.full_path
    ).inc()


@app.after_request
def after_request_metrics(response):
    duration = time.time() - g.start_time
    user_id = g.user_id
    session_id = g.session_id
    full_path = g.full_path
    method = request.method
    status = str(response.status_code)

    # Core labeled metrics
    http_requests_total.labels(
        method=method,
        user_id=user_id,
        session_id=session_id,
        path=full_path,
        status=status,
    ).inc()

    http_request_duration_seconds.labels(
        method=method,
        user_id=user_id,
        session_id=session_id,
        path=full_path,
    ).observe(duration)

    http_requests_in_progress.labels(
        user_id=user_id, path=full_path
    ).dec()

    # Track unique combinations
    combo = (user_id, full_path)
    if combo not in _seen_user_path_combos:
        _seen_user_path_combos.add(combo)
        unique_user_path_combinations.labels(
            user_id=user_id, path=full_path
        ).inc()

    # Dynamic per-user-path counter
    dynamic_counter = _get_or_create_dynamic_counter(user_id, full_path)
    if dynamic_counter is not http_requests_total:
        dynamic_counter.labels(method=method, status=status).inc()

    # Timestamp tracker
    user_last_request_timestamp.labels(
        user_id=user_id, path=full_path
    ).set(time.time())

    # Response size tracker
    content_length = response.content_length or 0
    http_response_bytes_total.labels(
        user_id=user_id, path=full_path
    ).inc(content_length)

    return response


