# ── Traffic simulator (optional helper) ────────────────────────────────────

def simulate_traffic(base_url: str = "http://localhost:5000", num_requests: int = 50):
    """Utility to generate sample traffic for testing."""
    import requests as req

    users = ["user_001", "user_002", "user_003", "anonymous"]
    sessions = [str(uuid.uuid4()) for _ in range(6)]
    paths = [
        "/",
        "/api/data",
        "/api/users/42/profile",
        "/api/search?q=python",
        "/api/search?q=prometheus",
        "/api/items/1",
        "/api/items/2",
        "/api/items/99",
        "/health",
    ]

    for i in range(num_requests):
        user = random.choice(users)
        session = random.choice(sessions)
        path = random.choice(paths)
        headers = {"X-User-Id": user, "X-Session-Id": session}

        try:
            resp = req.get(f"{base_url}{path}", headers=headers, timeout=5)
            print(f"[{i+1}/{num_requests}] {user} -> {path} => {resp.status_code}")
        except Exception as e:
            print(f"[{i+1}/{num_requests}] Error: {e}")

        time.sleep(random.uniform(0.05, 0.2))

    # Also send a POST
    headers = {"X-User-Id": "user_001", "X-Session-Id": sessions[0]}
    try:
        resp = req.post(f"{base_url}/api/checkout", headers=headers, json={"items": [1, 2]}, timeout=5)
        print(f"POST /api/checkout => {resp.status_code}")
    except Exception as e:
        print(f"POST Error: {e}")


